params.chat_id = $('Type Normalization').first().json.chat_id || 0;

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const bookingId = String(params.booking_id || '');

if (!uuidRegex.test(bookingId)) {
  throw {
    success: false,
    error_code: 'INVALID_BOOKING_ID',
    error_message: 'No se encontró un ID de reserva válido (UUID) en tu mensaje.'
  };
}

params.booking_id = bookingId;
return [{ json: params }];

